    constructor(isLeaf, val, topLeft = null, topRight = null, bottomLeft = null, bottomRight = null) {
        this.isLeaf = isLeaf;
        this.val = val;
        this.topLeft = topLeft;
        this.topRight = topRight;
        this.bottomLeft = bottomLeft;
        this.bottomRight = bottomRight;
    }
